1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const itemPremium = (item: Item): number => {
16	  const base = BASE_PREMIUMS[item.type];
17	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
18	  return base + firstInsuranceSurcharge;
19	};
20	
21	const quoteItems = (items: Item[]): number => {
22	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
23	  return Math.ceil(itemsTotal + PROCESSING_FEE);
24	};
25	
26	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
27	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
28	  return { results };
29	};
